window.__QUIZ_DATA__=[{"id":"theory>Physics>2009>1>a","subject":"Physics","year":"2009","type":"Theory","sub_label":"a","group":"","topic":"RECTILINEAR ACCELERATION : MOTION UNDER GRAVITY","question":"A particle is dropped from a vertical height h and falls freely for a time t.  With the aid of a sketch, explain how h varies with t","images":["data:image/png;base64,"],"marking_scheme":"The graph can be gotten from   x=ut+12at2  When the particle is dropped; it is assumed that  u = 0.  So,wehave:x=12at2  Let x = h.  So, we have: h=12at2    For h versus t2","marks":"2","difficulty":"2"},{"id":"theory>Physics>2009>1>b","subject":"Physics","year":"2009","type":"Theory","sub_label":"b","group":"","topic":"RECTILINEAR ACCELERATION : MOTION UNDER GRAVITY","question":"A particle is dropped from a vertical height h and falls freely for a time t.  With the aid of a sketch, explain how h varies with t2","images":["data:image/png;base64,"],"marking_scheme":"For h versus t","marks":"1","difficulty":"2"},{"id":"theory>Physics>2009>2","subject":"Physics","year":"2009","type":"Theory","sub_label":"2","group":"FINAL","topic":"PROJECTILE MOTION :","question":"A particle is projected horizontally at 15ms-1 from a height of 20m.   Calculate the horizontal distance covered by the particle just before hitting the ground.  [g = 10ms-2]","images":[],"marking_scheme":"Given:  - Velocity of projection, u = 15ms-1.  - Height of fall, H = 20m  - Horizontal distance (Range) = unknown = R  Recall: R = UT -----(1)  T=&radic;2Hg&nbsp;-----(2)  \u2234R=U&radic;2Hg&nbsp;  R=15&radic;2\u00d72010&nbsp;  R = 15&radic;4&nbsp; = 30m","marks":"3","difficulty":"3"},{"id":"theory>Physics>2009>3","subject":"Physics","year":"2009","type":"Theory","sub_label":"3","group":"CLOSENESS","topic":"CONCEPTS OF MATTER : CONCEPTS OF MATTER","question":"Explain why mercury does not wet glass while water does.","images":[],"marking_scheme":"- Mercury does not wet glass because the force of cohesion between the molecules of mercury is greater than the force of adhesion between mercury and glass.  - Water wet glass because the force of cohesion between the molecules of water is lesser than the force of adhesion between water and glass.","marks":"3","difficulty":"1"},{"id":"theory>Physics>2009>4>a","subject":"Physics","year":"2009","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"STRUCTURE OF THE ATOM : MODELS OF THE ATOM","question":"Explain what is meant by cations.","images":[],"marking_scheme":"Cations are ions that are positively charged.","marks":"2","difficulty":"1"},{"id":"theory>Physics>2009>4>b","subject":"Physics","year":"2009","type":"Theory","sub_label":"b","group":"","topic":"ELECTRIC FIELD : ELECTROSTATICS","question":"Draw and label an electrolytic cell.","images":["data:image/png;base64,"],"marking_scheme":"","marks":"2","difficulty":"2"},{"id":"theory>Physics>2009>5","subject":"Physics","year":"2009","type":"Theory","sub_label":"5","group":"CLOSENESS","topic":"LIGHT WAVES : DISPERSION OF WHITE LIGHT","question":"State three methods of polarizing an unpolarized light.","images":[],"marking_scheme":"Methods of polarizing an unpolarised light  - By reflection  - Double refraction  - The use of polaroid","marks":"3","difficulty":"2"},{"id":"theory>Physics>2009>6>a","subject":"Physics","year":"2009","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"ELECTRIC FIELD : ELECTROSTATICS","question":"State Faraday's second law of electrolysis.","images":[],"marking_scheme":"Faraday's Second Law of Electrolysis   \"Faraday's Second Law of Electrolysis\" passes through different electrolytes that are connected in series, the masses of the substances deposited is directly proportional to their chemical equivalents.","marks":"2","difficulty":"2"},{"id":"theory>Physics>2009>6>b","subject":"Physics","year":"2009","type":"Theory","sub_label":"b","group":"","topic":"ELECTRIC FIELD : ELECTROSTATICS","question":"An electric charge of 9.6 \u00d7 104C liberates 1 mole of a substance containing 6.0 \u00d7 1023 atoms. Determine the value of the electronic charge.","images":[],"marking_scheme":"Given:  - Change of an electron = ?  - Faraday's constant = 9.65 \u00d7 104  - Avogadro's number = 6.02 \u00d7 1023  Recall:chargeofanelectron=9.65\u00d71046.02\u00d71023  \u2248 1.60 \u00d7 10-19C","marks":"3","difficulty":"3"},{"id":"theory>Physics>2009>7>a","subject":"Physics","year":"2009","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"HOOKE\u2019S LAW, YOUNG\u2019S MODULES AND WORK DONE IN SPRINGS AND STRING :","question":"Explain the term tensile stress","images":[],"marking_scheme":"Tensile stress: This can be defined as the ratio of force to the cross-sectional area of the material.  - It is mathematically expressed as Tensile stress = ForceArea  - Its S.I unit is Nm-2.","marks":"2","difficulty":"2"},{"id":"theory>Physics>2009>7>b","subject":"Physics","year":"2009","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"HOOKE\u2019S LAW, YOUNG\u2019S MODULES AND WORK DONE IN SPRINGS AND STRING :","question":"Explain the term Young's modulus","images":[],"marking_scheme":"Young's Modulus: This is the ratio of tensile stress to tensile strain.","marks":"1","difficulty":"2"},{"id":"theory>Physics>2009>8>a","subject":"Physics","year":"2009","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"CONCEPTS OF MATTER : CONCEPTS OF MATTER","question":"Define diffusion.","images":[],"marking_scheme":"Diffusion: is the process through which the molecules of a solute move from a region of higher concentration to a region of lower concentration.  It can also be defined as the intermingling of the molecules of a fluid due to random thermal agitation.","marks":"2","difficulty":"1"},{"id":"theory>Physics>2009>8>b","subject":"Physics","year":"2009","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"ELECTRIC FIELD : ELECTRIC CONDUCTION THROUGH MATERIALS","question":"State two applications of electrical conduction through gases.","images":[],"marking_scheme":"Application of Electrical Conduction Through Gases   1. It is used in lighting i.e fluorescent tubes.  2. It is used in the identification of gases.   3. It is also used in TV tubes.","marks":"2","difficulty":"2"},{"id":"theory>Physics>2009>9>a","subject":"Physics","year":"2009","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"STRUCTURE OF THE ATOM : CATHODE RAYS","question":"List two properties of cathode rays.","images":[],"marking_scheme":"Properties of Cathode Rays   1. They are negatively charged  2. They cause the rotation of mechanical paddle wheel place along their path of propagation","marks":"2","difficulty":"2"},{"id":"theory>Physics>2009>9>b","subject":"Physics","year":"2009","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"STRUCTURE OF THE ATOM : CATHODE RAYS","question":"Explain how the intensity and energy of cathode rays may be increased.","images":[],"marking_scheme":"- The intensity of cathode rays can be increased by an increase in the temperature of the cathode or through an increase in the current that passes through the heater.  - The energy of cathode rays can be increased by raising the potential difference between the terminals (anode and cathode).","marks":"3","difficulty":"3"},{"id":"theory>Physics>2009>10","subject":"Physics","year":"2009","type":"Theory","sub_label":"10","group":"CLOSENESS","topic":"WAVE-PARTICLE PARADOX : DUALITY OF MATTER","question":"Give three observation in support of de Broglie's assumption that moving particles behave like waves.","images":[],"marking_scheme":"OBSERVATION IN SUPPORT OF DE BROGILE'S ASSUMPTION   1. Electrons can be refracted   2. Electrons can be reflected   3. Electrons can be interfered","marks":"4","difficulty":"3"},{"id":"theory>Physics>2009>11>a","subject":"Physics","year":"2009","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"EQUILIBRIUM OF FORCES : CENTRE OF GRAVITY AND STABILITY","question":"Give a retort stand and clamp, a stout pin, a simple pendulum and a pencil, describe how you would use these apparatus to determine the centre of gravity of an irregularly shaped piece of cardboard of a moderate size.   State two precautions necessary to obtain accurate results.","images":[],"marking_scheme":"Procedure:   Fix three pinholes round the edge of the cardboard. Clamp the pin horizontally, then suspend the cardboard on it through one of the pinholes, so that the cardboard swing freely. Hang the simple pendulum on the same pin and allow its string to be closed to the cardboard. When the whole system is at rest trace the plumbline on the cardboard. Repeat the procedure for each of the two other pin holes.  It should be noted that, the point of intersection of the three traced lines is the centre of gravity of the cardboard.     Precautions:   The precautions taken during the experiment include:  1. Ensure that the string is closed to the cardboard.  2. Ensure that the simple penulum rests before tracing the plumb line on the cardboard.","marks":"3","difficulty":"2"},{"id":"theory>Physics>2009>11>b>i","subject":"Physics","year":"2009","type":"Theory","sub_label":"i","group":"","topic":"RECTILINEAR ACCELERATION : VELOCITY-TIME GRAPH","question":"Using a suitable diagram, explain how the following can be obtained form a velocity-time graph acceleration","images":["data:image/png;base64,"],"marking_scheme":"Acceleration:   Between O and A, the body is accelerating.  \u2234acceleration=VA - VotA - to  VA = V1, Vo = 0; tA = t1; to = 0  \u2234a=V1 - 0t1 - 0","marks":"2","difficulty":"2"},{"id":"theory>Physics>2009>11>b>ii","subject":"Physics","year":"2009","type":"Theory","sub_label":"ii","group":"","topic":"RECTILINEAR ACCELERATION : VELOCITY-TIME GRAPH","question":"Using a suitable diagram, explain how the following can be obtained form a velocity-time graph total distance covered.","images":["data:image/png;base64,"],"marking_scheme":"Distance:   The distance covered by the body is the area under the graph.  \u2234 Distance, S = Area of \u0394OAt1 + Area of At1t2B + Area of \u0394Bt2O.","marks":"3","difficulty":"2"},{"id":"theory>Physics>2009>11>c>i","subject":"Physics","year":"2009","type":"Theory","sub_label":"i","group":"FINAL","topic":"RECTILINEAR ACCELERATION : CONCEPT OF ACCELERATION/DECELERATION","question":"A body at rest is given an initial uniform acceleration of 6.0ms-2 for 20s after which the acceleration is reduced to 4.0ms-2 for the next 10s.  The body maintains the speed attained for 30s.   Draw the velocity-time graph of the motion using the information given above. From the graph, calculate the maximum speed attained during the motion","images":[],"marking_scheme":"Given: The information in the question. Diagrammatically, we have:     - For the first acceleration  6=V1 - 020  V1 = 120ms-1    - For the second acceleration  4=V2 - V130 - 20  \u22344=V2 - V110  40 = V2 - V1 (Since V1 = 120ms-1)  V2 = 40 + V1 = 40 + 120  \u2234 V2 = 160ms-1    Hence, the maximum speed = 160ms-1","marks":"2","difficulty":"3"},{"id":"theory>Physics>2009>11>c>ii","subject":"Physics","year":"2009","type":"Theory","sub_label":"ii","group":"FINAL","topic":"RECTILINEAR ACCELERATION : VELOCITY-TIME GRAPH","question":"A body at rest is given an initial uniform acceleration of 6.0ms-2 for 20s after which the acceleration is reduced to 4.0ms-2 for the next 10s.  The body maintains the speed attained for 30s.   Draw the velocity-time graph of the motion using the information given above. From the graph, calculate the total distance travelled during the first 30s","images":[],"marking_scheme":"Distance travelled during the first 30s of the journey.  Distance = Area of \u0394 at t = 20s + Area of \u0394 between t = 20s and t = 30s + Area of rectangle between t = 20s and t = 30s.  \u2234Distance=(12\u00d720\u00d7120)+(12\u00d710\u00d740)+(120\u00d710)  = 1200 + 200 + 1200  = 2600m","marks":"2","difficulty":"3"},{"id":"theory>Physics>2009>11>c>iii","subject":"Physics","year":"2009","type":"Theory","sub_label":"iii","group":"FINAL","topic":"RECTILINEAR ACCELERATION : VELOCITY-TIME GRAPH","question":"A body at rest is given an initial uniform acceleration of 6.0ms-2 for 20s after which the acceleration is reduced to 4.0ms-2 for the next 10s.  The body maintains the speed attained for 30s.   Draw the velocity-time graph of the motion using the information given above. From the graph, calculate the average speed during the same time interval as in (ii) above.","images":[],"marking_scheme":"Average speed for the first 30s of the journey.  Recall:Averagespeed=Distancetime  \u2234Averagespeedforthefirst30s=Distance for the first 30s30  =260030 = 86.7ms-1","marks":"2","difficulty":"3"},{"id":"theory>Physics>2009>12>a","subject":"Physics","year":"2009","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"HEAT ENERGY : BOILING POINT","question":"Explain why is not advisable to sterilize a clinical thermometer in boiling water at normal atmosphere pressure.","images":[],"marking_scheme":"Operational Deviation attached to the sterilization of a chemical thermometer in boiling water at atm.   - The temperature range of a clinical thermometer is usually small. If placed in boiling water at normal atmospheric pressure (atm.), the mercury will expand and exert pressure on the glass, consequently, the glass will crack or burst.","marks":"3","difficulty":"2"},{"id":"theory>Physics>2009>12>b>i","subject":"Physics","year":"2009","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"HEAT ENERGY : BOILING POINT","question":"State the effect of an increase in pressure on the boiling point","images":[],"marking_scheme":"Effect of pressure increase   - On boiling point of water: Pressure increases the boiling point of water.","marks":"2","difficulty":"2"},{"id":"theory>Physics>2009>12>b>ii","subject":"Physics","year":"2009","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"HEAT ENERGY : MELTING POINT","question":"State the effect of an increase in pressure on the melting point of water","images":[],"marking_scheme":"Effect of pressure increase   - On melting point of water & increase in pressure  decreases the melting point of water.","marks":"2","difficulty":"2"},{"id":"theory>Physics>2009>12>c","subject":"Physics","year":"2009","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"HEAT ENERGY : VAPOUR AND VAPOUR PRESSURE","question":"S.V.P (mmHg)    The graph shown above is that of the saturated vapour pressure (svp) of water against temperature.  Pure water is known to boil at 100oC and at an atmospheric pressure of 760mmHg. What general conclusion can be drawn form the information given above and from the graph?","images":["data:image/png;base64,"],"marking_scheme":"Given:  The graph in the question   - Water boils at the temperature when its SVP is equal to the atmospheric pressure.","marks":"2","difficulty":"3"},{"id":"theory>Physics>2009>12>d>i","subject":"Physics","year":"2009","type":"Theory","sub_label":"i","group":"FINAL","topic":"FLUID AT REST : PRESSURE IN FLUIDS","question":"A thread of mercury of length 20cm is used to trap some air in a capillary tube with uniform cross-sectional area and closed at one end. With the tube vertical and the open end uppermost, the length of the trapped air column is 15cm. Calculate the length of the air column when the tube is held    horizontally  [Atmospheric pressure = 76cmHg]","images":["data:image/png;base64,","data:image/png;base64,","data:image/png;base64,"],"marking_scheme":"Given: The stated positions of the tube.  When the tube is held vertically with the open end facing up.  When the tube is held horizontally Boyle's Law is to be applied  P\u03b11V  P1V1 = P2V2 = P3V3 ...... PnVn  Recall that: V = A \u00d7 L  \u2234 We have: P1A1L1 = P2A2L2 = P3A3L3  A1 = A2 = A3 = A {Area of cross-section of tube is constant}  P1AL1 = P2AL2 = P3AL3  \u2234 P1AL1 = P2AL2  P1L1 = P2L2 ......(1)  P1L1 = P3L3 ......(2)  P2L2 = P3L3 ......(3)  P1 = Pa + Pm   \u2234 P1 = 76 + 20 = 96 cmHg    P2 = Pm = 76 ......  \u2234 P2 = 76  P3 = -Pm + Pa  \u2234 P3 = -20 + 76 = 56  \u2234 P1L1 = P2L2  96 \u00d7 15 = 76L2  L2 = 18.95cm","marks":"1","difficulty":"2"},{"id":"theory>Physics>2009>12>d>ii","subject":"Physics","year":"2009","type":"Theory","sub_label":"ii","group":"FINAL","topic":"FLUID AT REST : PRESSURE IN FLUIDS","question":"A thread of mercury of length 20cm is used to trap some air in a capillary tube with uniform cross-sectional area and closed at one end. With the tube vertical and the open end uppermost, the length of the trapped air column is 15cm. Calculate the length of the air column when the tube is held   vertically with the open end underneath.  [Atmospheric pressure = 76cmHg]","images":[],"marking_scheme":"When the tube is vertically positioned with the open end underneath, {when the tube is inverted}  Boyle's Law is to be applied  P\u03b11V  P1V1 = P2V2 = P3V3 ...... PnVn  Recall that: V = A \u00d7 L  \u2234 We have: P1A1L1 = P2A2L2 = P3A3L3  A1 = A2 = A3 = A {Area of cross-section of tube is constant}  P1AL1 = P2AL2 = P3AL3  \u2234 P1AL1 = P2AL2  P1L1 = P2L2 ......(1)  P1L1 = P3L3 ......(2)  P2L2 = P3L3 ......(3)  P1 = Pa + Pm   \u2234 P1 = 76 + 20 = 96 cmHg    From (2)  P1L1 = P3L3  96 \u00d7 15 = 56L3  L3 = 25.71cm","marks":"4","difficulty":"2"},{"id":"theory>Physics>2009>13>a","subject":"Physics","year":"2009","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"SOUND WAVES : CHARACTERISTICS OF SOUND","question":"State two differences between a sound wave and a radio wave.","images":[],"marking_scheme":"Differences between sound waves and radio waves  Sound wavesRadio waves1. Sound waves require material medium i.e they are mechanicalRadio waves do not require material medium, i.e they are electromagneticThey travel with speeds less than the speed of lightThey travel with the speed of light","marks":"3","difficulty":"1"},{"id":"theory>Physics>2009>13>b","subject":"Physics","year":"2009","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"SOUND WAVES : FORCED VIBRATION","question":"Explain why a vibrating tuning fork sounds louder when its stem is pressed against a table top than when held in air.","images":[],"marking_scheme":"The vibrating tuning fork forces the table top to vibrate, since the table top has a larger area, it  is therefore in contact with larger volume of air, undergoing vibration, hence, sound heard is amplified.","marks":"2","difficulty":"1"},{"id":"theory>Physics>2009>13>c>i","subject":"Physics","year":"2009","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"PRODUCTION AND PROPAGATION OF WAVES : PRODUCTION AND PROPAGATION OF MECHANICAL WAVES","question":"State two conditions necessary for the production of stationary wave in a medium;","images":[],"marking_scheme":"Conditions necessary for the production of stationary wave   1. The incident and reflected waves must have the same amplitude.  2. There must be superimposition","marks":"1","difficulty":"2"},{"id":"theory>Physics>2009>13>c>ii","subject":"Physics","year":"2009","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"PROPERTIES OF WAVES : INTERFERENCE","question":"State two conditions necessary for the formation of interference wave patterns;","images":[],"marking_scheme":"Conditions necessary for the production of interference wave patterns   1. Two sources are usually involved  2. The interfering must have the same amplitude","marks":"1","difficulty":"2"},{"id":"theory>Physics>2009>13>c>iii","subject":"Physics","year":"2009","type":"Theory","sub_label":"iii","group":"CLOSENESS","topic":"LIGHT WAVES : REFRACTION OF LIGHT AT PLANE SURFACES","question":"State two conditions necessary for the occurrence of total internal reflection of wave.","images":[],"marking_scheme":"Conditions necessary for the occurrence of the total internal reflection   1. Two media are involved.  2. The wave should be travelling from a denser medium to a less dense medium  3. The angle of incidence in the denser medium must be greater than the critical angle.","marks":"1","difficulty":"2"},{"id":"theory>Physics>2009>13>d>i","subject":"Physics","year":"2009","type":"Theory","sub_label":"i","group":"","topic":"LIGHT WAVES : REFRACTION OF LIGHT AT CURVED SURFACES","question":"A ray of light is incident on one face of an equilateral glass prism.  Draw a ray diagram to show the path of the ray through the prism.","images":["data:image/png;base64,"],"marking_scheme":"","marks":"3","difficulty":"3"},{"id":"theory>Physics>2009>13>d>ii","subject":"Physics","year":"2009","type":"Theory","sub_label":"ii","group":"FINAL","topic":"LIGHT WAVES : REFRACTION OF LIGHT AT CURVED SURFACES","question":"A ray of light is incident on one face of an equilateral glass prism.  Calculate the refractive index of the glass if the angle of minimum deviation is 41\u00b0.","images":[],"marking_scheme":"Recall:Refractiveindex,n=Sin(A + Dm)/2sin(A/2)    A = Angle of Deviation  Dm = Minimum deviation  A = 60\u00b0, Dm = 41\u00b0  n=sin(60+41)/2sin60/2  n = 1.54","marks":"3","difficulty":"3"},{"id":"theory>Physics>2009>14>a","subject":"Physics","year":"2009","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"ELECTRIC FIELD : ELECTRIC CIRCUIT","question":"State two essential differences between a moving coil galvanometer and a d.c generator.","images":[],"marking_scheme":"Differences between a moving coil galvanometer and a d.c generator.   Moving Coil GalvanometerD.C Generator1. Hair springs are present  2.  Incomplete rotation of coil  3. Converts electrical energy to mechanical energySplit rings or commutators are present  Continuous rotation of coil  Converts mechanical energy to electrical energy","marks":"3","difficulty":"2"},{"id":"theory>Physics>2009>14>b","subject":"Physics","year":"2009","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"ELECTROMAGNETIC FIELD : EDDY CURRENTS","question":"Explain the term eddy currents and state two devices in which the current are applied.","images":[],"marking_scheme":"Eddy Current: (A) Meaning and Fields (Source) of Application   They are currents induced in a conductor when it is exposed to varying magnetic field. It should be noted that eddy current produces heat; also Eddy current cannot pass through gaps and also pass in a circular trajectory or closed loops.     B. Fields of Application   1. Electric motor brakes  2. Speedometres in automobiles  3. Pointers of electric metres  4. Mass balances","marks":"3","difficulty":"2"},{"id":"theory>Physics>2009>14>c","subject":"Physics","year":"2009","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"ELECTRIC FIELD : POTENTIAL DIFFERENCE AND ELECTRIC CURRENT","question":"State the principle on which the potentiometer is based when it is functioning.","images":[],"marking_scheme":"WORKING PRINCIPLE OF POTENTIOMETER  The working/functioning of the potentiometer is based on the principle that the potential difference across a length of a wire is directly proportional to the length provided the wire has a uniform cross-section.","marks":"2","difficulty":"2"},{"id":"theory>Physics>2009>14>d>i","subject":"Physics","year":"2009","type":"Theory","sub_label":"i","group":"","topic":"SIMPLE A.C. CIRCUITS : VECTOR DIAGRAMS","question":"A source of e.m.f 110V and frequency 60Hz is connected to a resistor, an inductor and a capacitor in series. When the current in the capacitor 2A, the potential difference across the resistor is 80V and that across the inductor is 40V. Draw the vector diagram of the potential differences across the resistor is 80V and that across the inductor is 40V. Draw the vector diagram of the potential differences across the inductor, the capacitor and the resistor. [\u03c0 = 3.14]    Calculate the potential difference across the capacitor;","images":["data:image/png;base64,"],"marking_scheme":"From the vector diagram,  \u2211Vy = VL - VC ; \u2211Vx = VR  \u2234V2 = (\u2211Vy)2 + (\u2211Vx)2  V2 = (VL - VC)2 + VR2 ....... (1)  Given: V = 110V, VR = 80V; VL = 40V  From (1), V2 = (VL - VC)2 + VR2  (110)2 = (40 - VC)2 + (80)2  12100 = (40 - VC)2 + 6400  (40 - VC)2 = 5700  40 - VC = &radic;5700&nbsp;  40 - VC = \u00b175.5  40 - VC = +75.5 .......(2)  or   40 - VC = -75.5 ...... (3)  From (2), VC = -35.5V  From (3), VC = 115.5V","marks":"2","difficulty":"3"},{"id":"theory>Physics>2009>14>d>ii","subject":"Physics","year":"2009","type":"Theory","sub_label":"ii","group":"FINAL","topic":"SIMPLE A.C. CIRCUITS : VECTOR DIAGRAMS","question":"A source of e.m.f 110V and frequency 60Hz is connected to a resistor, an inductor and a capacitor in series. When the current in the capacitor 2A, the potential difference across the resistor is 80V and that across the inductor is 40V. Draw the vector diagram of the potential differences across the resistor is 80V and that across the inductor is 40V. Draw the vector diagram of the potential differences across the inductor, the capacitor and the resistor. [\u03c0 = 3.14]  Calculate the capacitance of the capacitor;","images":[],"marking_scheme":"Capacitance, C is unknown  Recall: XC = 1/a\u03c0fC ....... (1)  XC=VCI.....(2)  \u223412\u03c0fC=VCI  I = 2\u03c0fC VC  \u2234C=I2\u03c0fVC  \u2234C=22 \u00d7 3.142 \u00d7 60 \u00d7 115.5  C=26.284\u00d7 6930  C=243,548.12  C = 4.59 \u00d7 10-5 F  \u2234 C \u2248 45.9 \u00d7 10-6F  C \u2248 45.9\u03bcF","marks":"2","difficulty":"3"},{"id":"theory>Physics>2009>14>d>iii","subject":"Physics","year":"2009","type":"Theory","sub_label":"iii","group":"","topic":"SIMPLE A.C. CIRCUITS : VECTOR DIAGRAMS","question":"A source of e.m.f 110V and frequency 60Hz is connected to a resistor, an inductor and a capacitor in series. When the current in the capacitor 2A, the potential difference across the resistor is 80V and that across the inductor is 40V. Draw the vector diagram of the potential differences across the resistor is 80V and that across the inductor is 40V. Draw the vector diagram of the potential differences across the inductor, the capacitor and the resistor. [\u03c0 = 3.14]  Calculate the inductance of the inductor.","images":[],"marking_scheme":"Inductance, L of inductor.  Recall: XL = 2\u03c0fL ....... (1)  XL=VLI......(2)  \u22342\u03c0fL=VLI  2\u03c0fL=VLI  2\u03c0fLI = VL  \u2234L=VL2\u03c0fI  L=402 \u00d7 3.142 \u00d7 60 \u00d72  L=406.284 \u00d7 120  L=407.5 \u00d7 102  L = 5.3 \u00d7 10-2H","marks":"2","difficulty":"3"},{"id":"theory>Physics>2009>15>a>i","subject":"Physics","year":"2009","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"STRUCTURE OF THE ATOM : ENERGY QUANTIZATION","question":"Briefly explain this term emission line spectra.","images":[],"marking_scheme":"Emission Line Spectra : This is composed mainly of distinct an segregated bright lines of definite wavelength on a dark background.  The production of line spectra is a result of dispersion which is undergone by light from a luminous source.","marks":"3","difficulty":"2"},{"id":"theory>Physics>2009>15>a>ii","subject":"Physics","year":"2009","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"STRUCTURE OF THE ATOM : ENERGY QUANTIZATION","question":"Briefly explain this term line absorption spectra","images":[],"marking_scheme":"Line Absorption Spectra: This is usually obtained when light passes through a cool gas and as a result certain wavelengths of the light area absorbed. Consequently, series of dark lines, each corresponding to one of the wavelengths absorbed are formed.","marks":"2","difficulty":"2"},{"id":"theory>Physics>2009>15>b","subject":"Physics","year":"2009","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"INTRODUCTION TO LASER :","question":"Draw a labelled diagram showing the structure of a simple type of photocell and explain its mode of operation.","images":["data:image/png;base64,"],"marking_scheme":"Mode of Operation   When radiations of useful frequencies falls on the cathode there is usually an emission of electrons. Due to the positive nature of the anode, the electrons are attached to the anode. It should be noted that the electron flow completes the circuit.","marks":"3","difficulty":"2"},{"id":"theory>Physics>2009>15>c>i","subject":"Physics","year":"2009","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"STRUCTURE OF THE ATOM : X-RAYS","question":"State two reasons to show that x-rays are waves","images":[],"marking_scheme":"Wave nature of X-rays  - Reflection  - Refraction  - Polarization  - Interference  - Diffraction","marks":"3","difficulty":"2"},{"id":"theory>Physics>2009>15>c>ii","subject":"Physics","year":"2009","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"STRUCTURE OF THE ATOM : X-RAYS","question":"State two uses of x-rays other than in medicine.","images":[],"marking_scheme":"Other uses of X-rays other than medicine include:  1. Crystal Lattices study  2. Security  3. Detection of cracks in  metals  4. To detect the strength and genuineness of artistic works.","marks":"1","difficulty":"1"},{"id":"theory>Physics>2009>15>d","subject":"Physics","year":"2009","type":"Theory","sub_label":"d","group":"","topic":"STRUCTURE OF THE ATOM : ENERGY QUANTIZATION","question":"An electron jumps from an energy level of -1.6eV to one of -10.4eV in an atom. Calculate the energy and wavelength of the emitted radiation.  [h = 6.6 \u00d7 10-34Js, c = 3.00 \u00d7 108ms-1; eV = 1.6 \u00d7 10-19J]","images":[],"marking_scheme":"Given: There is a reduction in the energy level of the electron from -1.6eV to -10.4eV.  (1.) h = 6.6 \u00d7 10-34Js (2) c = 3 \u00d7 108ms-1 (3) 1eV 1.6 \u00d7 1019Js    \u2234 Wavelength and Energy of emitted radiation = ?  From the illustration above, \u0394E = Ei - Ef  = (-1.6) - (-10.4) = 8.8eV or  since 1e = 1.6 \u00d7 10-19C  \u2234 8eV = 8.8 \u00d7 1.6 \u00d7 10-19C  = 1.41 \u00d7 10-18J   - Wavelength of emitted radiation, \u03bb  Recall, E=hf=hc\u03bb  \u03bb=hcE  =6.6 \u00d7 10-34 \u00d7 3 \u00d7 1081.41 \u00d7 10-8  \u03bb = 14.04 \u00d7 10-8m","marks":"3","difficulty":"3"}];